1	use crate::session::Session;
2	
3	const DEFAULT_INPUT_COST_PER_MILLION: f64 = 15.0;
4	const DEFAULT_OUTPUT_COST_PER_MILLION: f64 = 75.0;
5	const DEFAULT_CACHE_CREATION_COST_PER_MILLION: f64 = 18.75;
6	const DEFAULT_CACHE_READ_COST_PER_MILLION: f64 = 1.5;
7	
8	/// Per-million-token pricing used for cost estimation.
9	#[derive(Debug, Clone, Copy, PartialEq)]
10	pub struct ModelPricing {
11	    pub input_cost_per_million: f64,
12	    pub output_cost_per_million: f64,
13	    pub cache_creation_cost_per_million: f64,
14	    pub cache_read_cost_per_million: f64,
15	}
16	
17	impl ModelPricing {
18	    #[must_use]
19	    pub const fn default_sonnet_tier() -> Self {
20	        Self {
21	            input_cost_per_million: DEFAULT_INPUT_COST_PER_MILLION,
22	            output_cost_per_million: DEFAULT_OUTPUT_COST_PER_MILLION,
23	            cache_creation_cost_per_million: DEFAULT_CACHE_CREATION_COST_PER_MILLION,
24	            cache_read_cost_per_million: DEFAULT_CACHE_READ_COST_PER_MILLION,
25	        }
26	    }
27	}
28	
29	/// Token counters accumulated for a conversation turn or session.
30	#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
31	pub struct TokenUsage {
32	    pub input_tokens: u32,
33	    pub output_tokens: u32,
34	    pub cache_creation_input_tokens: u32,
35	    pub cache_read_input_tokens: u32,
36	}
37	
38	/// Estimated dollar cost derived from a [`TokenUsage`] sample.
39	#[derive(Debug, Clone, Copy, PartialEq)]
40	pub struct UsageCostEstimate {
41	    pub input_cost_usd: f64,
42	    pub output_cost_usd: f64,
43	    pub cache_creation_cost_usd: f64,
44	    pub cache_read_cost_usd: f64,
45	}
46	
47	impl UsageCostEstimate {
48	    #[must_use]
49	    pub fn total_cost_usd(self) -> f64 {
50	        self.input_cost_usd
51	            + self.output_cost_usd
52	            + self.cache_creation_cost_usd
53	            + self.cache_read_cost_usd
54	    }
55	}
56	
57	/// Returns pricing metadata for a known model alias or family.
58	#[must_use]
59	pub fn pricing_for_model(model: &str) -> Option<ModelPricing> {
60	    let normalized = model.to_ascii_lowercase();
61	    if normalized.contains("haiku") {
62	        return Some(ModelPricing {
63	            input_cost_per_million: 1.0,
64	            output_cost_per_million: 5.0,
65	            cache_creation_cost_per_million: 1.25,
66	            cache_read_cost_per_million: 0.1,
67	        });
68	    }
69	    if normalized.contains("opus") {
70	        return Some(ModelPricing {
71	            input_cost_per_million: 15.0,
72	            output_cost_per_million: 75.0,
73	            cache_creation_cost_per_million: 18.75,
74	            cache_read_cost_per_million: 1.5,
75	        });
76	    }
77	    if normalized.contains("sonnet") {
78	        return Some(ModelPricing::default_sonnet_tier());
79	    }
80	    None
81	}
82	
83	impl TokenUsage {
84	    #[must_use]
85	    pub fn total_tokens(self) -> u32 {
86	        self.input_tokens
87	            + self.output_tokens
88	            + self.cache_creation_input_tokens
89	            + self.cache_read_input_tokens
90	    }
91	
92	    #[must_use]
93	    pub fn estimate_cost_usd(self) -> UsageCostEstimate {
94	        self.estimate_cost_usd_with_pricing(ModelPricing::default_sonnet_tier())
95	    }
96	
97	    #[must_use]
98	    pub fn estimate_cost_usd_with_pricing(self, pricing: ModelPricing) -> UsageCostEstimate {
99	        UsageCostEstimate {
100	            input_cost_usd: cost_for_tokens(self.input_tokens, pricing.input_cost_per_million),
101	            output_cost_usd: cost_for_tokens(self.output_tokens, pricing.output_cost_per_million),
102	            cache_creation_cost_usd: cost_for_tokens(
103	                self.cache_creation_input_tokens,
104	                pricing.cache_creation_cost_per_million,
105	            ),
106	            cache_read_cost_usd: cost_for_tokens(
107	                self.cache_read_input_tokens,
108	                pricing.cache_read_cost_per_million,
109	            ),
110	        }
111	    }
112	
113	    #[must_use]
114	    pub fn summary_lines(self, label: &str) -> Vec<String> {
115	        self.summary_lines_for_model(label, None)
116	    }
117	
118	    #[must_use]
119	    pub fn summary_lines_for_model(self, label: &str, model: Option<&str>) -> Vec<String> {
120	        let pricing = model.and_then(pricing_for_model);
121	        let cost = pricing.map_or_else(
122	            || self.estimate_cost_usd(),
123	            |pricing| self.estimate_cost_usd_with_pricing(pricing),
124	        );
125	        let model_suffix =
126	            model.map_or_else(String::new, |model_name| format!(" model={model_name}"));
127	        let pricing_suffix = if pricing.is_some() {
128	            ""
129	        } else if model.is_some() {
130	            " pricing=estimated-default"
131	        } else {
132	            ""
133	        };
134	        vec![
135	            format!(
136	                "{label}: total_tokens={} input={} output={} cache_write={} cache_read={} estimated_cost={}{}{}",
137	                self.total_tokens(),
138	                self.input_tokens,
139	                self.output_tokens,
140	                self.cache_creation_input_tokens,
141	                self.cache_read_input_tokens,
142	                format_usd(cost.total_cost_usd()),
143	                model_suffix,
144	                pricing_suffix,
145	            ),
146	            format!(
147	                "  cost breakdown: input={} output={} cache_write={} cache_read={}",
148	                format_usd(cost.input_cost_usd),
149	                format_usd(cost.output_cost_usd),
150	                format_usd(cost.cache_creation_cost_usd),
151	                format_usd(cost.cache_read_cost_usd),
152	            ),
153	        ]
154	    }
155	}
156	
157	fn cost_for_tokens(tokens: u32, usd_per_million_tokens: f64) -> f64 {
158	    f64::from(tokens) / 1_000_000.0 * usd_per_million_tokens
159	}
160	
161	#[must_use]
162	/// Formats a dollar-denominated value for CLI display.
163	pub fn format_usd(amount: f64) -> String {
164	    format!("${amount:.4}")
165	}
166	
167	/// Aggregates token usage across a running session.
168	#[derive(Debug, Clone, Default, PartialEq, Eq)]
169	pub struct UsageTracker {
170	    latest_turn: TokenUsage,
171	    cumulative: TokenUsage,
172	    turns: u32,
173	}
174	
175	impl UsageTracker {
176	    #[must_use]
177	    pub fn new() -> Self {
178	        Self::default()
179	    }
180	
181	    #[must_use]
182	    pub fn from_session(session: &Session) -> Self {
183	        let mut tracker = Self::new();
184	        for message in &session.messages {
185	            if let Some(usage) = message.usage {
186	                tracker.record(usage);
187	            }
188	        }
189	        tracker
190	    }
191	
192	    pub fn record(&mut self, usage: TokenUsage) {
193	        self.latest_turn = usage;
194	        self.cumulative.input_tokens += usage.input_tokens;
195	        self.cumulative.output_tokens += usage.output_tokens;
196	        self.cumulative.cache_creation_input_tokens += usage.cache_creation_input_tokens;
197	        self.cumulative.cache_read_input_tokens += usage.cache_read_input_tokens;
198	        self.turns += 1;
199	    }
200	
201	    #[must_use]
202	    pub fn current_turn_usage(&self) -> TokenUsage {
203	        self.latest_turn
204	    }
205	
206	    #[must_use]
207	    pub fn cumulative_usage(&self) -> TokenUsage {
208	        self.cumulative
209	    }
210	
211	    #[must_use]
212	    pub fn turns(&self) -> u32 {
213	        self.turns
214	    }
215	}
