218	mod tests {
219	    use super::{format_usd, pricing_for_model, TokenUsage, UsageTracker};
220	    use crate::session::{ContentBlock, ConversationMessage, MessageRole, Session};
221	
222	    #[test]
223	    fn tracks_true_cumulative_usage() {
224	        let mut tracker = UsageTracker::new();
225	        tracker.record(TokenUsage {
226	            input_tokens: 10,
227	            output_tokens: 4,
228	            cache_creation_input_tokens: 2,
229	            cache_read_input_tokens: 1,
230	        });
231	        tracker.record(TokenUsage {
232	            input_tokens: 20,
233	            output_tokens: 6,
234	            cache_creation_input_tokens: 3,
235	            cache_read_input_tokens: 2,
236	        });
237	
238	        assert_eq!(tracker.turns(), 2);
239	        assert_eq!(tracker.current_turn_usage().input_tokens, 20);
240	        assert_eq!(tracker.current_turn_usage().output_tokens, 6);
241	        assert_eq!(tracker.cumulative_usage().output_tokens, 10);
242	        assert_eq!(tracker.cumulative_usage().input_tokens, 30);
243	        assert_eq!(tracker.cumulative_usage().total_tokens(), 48);
244	    }
245	
246	    #[test]
247	    fn computes_cost_summary_lines() {
248	        let usage = TokenUsage {
249	            input_tokens: 1_000_000,
250	            output_tokens: 500_000,
251	            cache_creation_input_tokens: 100_000,
252	            cache_read_input_tokens: 200_000,
253	        };
254	
255	        let cost = usage.estimate_cost_usd();
256	        assert_eq!(format_usd(cost.input_cost_usd), "$15.0000");
257	        assert_eq!(format_usd(cost.output_cost_usd), "$37.5000");
258	        let lines = usage.summary_lines_for_model("usage", Some("claude-sonnet-4-20250514"));
259	        assert!(lines[0].contains("estimated_cost=$54.6750"));
260	        assert!(lines[0].contains("model=claude-sonnet-4-20250514"));
261	        assert!(lines[1].contains("cache_read=$0.3000"));
262	    }
263	
264	    #[test]
265	    fn supports_model_specific_pricing() {
266	        let usage = TokenUsage {
267	            input_tokens: 1_000_000,
268	            output_tokens: 500_000,
269	            cache_creation_input_tokens: 0,
270	            cache_read_input_tokens: 0,
271	        };
272	
273	        let haiku = pricing_for_model("claude-haiku-4-5-20251001").expect("haiku pricing");
274	        let opus = pricing_for_model("claude-opus-4-6").expect("opus pricing");
275	        let haiku_cost = usage.estimate_cost_usd_with_pricing(haiku);
276	        let opus_cost = usage.estimate_cost_usd_with_pricing(opus);
277	        assert_eq!(format_usd(haiku_cost.total_cost_usd()), "$3.5000");
278	        assert_eq!(format_usd(opus_cost.total_cost_usd()), "$52.5000");
279	    }
280	
281	    #[test]
282	    fn marks_unknown_model_pricing_as_fallback() {
283	        let usage = TokenUsage {
284	            input_tokens: 100,
285	            output_tokens: 100,
286	            cache_creation_input_tokens: 0,
287	            cache_read_input_tokens: 0,
288	        };
289	        let lines = usage.summary_lines_for_model("usage", Some("custom-model"));
290	        assert!(lines[0].contains("pricing=estimated-default"));
291	    }
292	
293	    #[test]
294	    fn reconstructs_usage_from_session_messages() {
295	        let mut session = Session::new();
296	        session.messages = vec![ConversationMessage {
297	            role: MessageRole::Assistant,
298	            blocks: vec![ContentBlock::Text {
299	                text: "done".to_string(),
300	            }],
301	            usage: Some(TokenUsage {
302	                input_tokens: 5,
303	                output_tokens: 2,
304	                cache_creation_input_tokens: 1,
305	                cache_read_input_tokens: 0,
306	            }),
307	        }];
308	
309	        let tracker = UsageTracker::from_session(&session);
310	        assert_eq!(tracker.turns(), 1);
311	        assert_eq!(tracker.cumulative_usage().total_tokens(), 8);
312	    }
313	}
