118	    #[must_use]
119	    pub fn summary_lines_for_model(self, label: &str, model: Option<&str>) -> Vec<String> {
120	        let pricing = model.and_then(pricing_for_model);
121	        let cost = pricing.map_or_else(
122	            || self.estimate_cost_usd(),
123	            |pricing| self.estimate_cost_usd_with_pricing(pricing),
124	        );
125	        let model_suffix =
126	            model.map_or_else(String::new, |model_name| format!(" model={model_name}"));
127	        let pricing_suffix = if pricing.is_some() {
128	            ""
129	        } else if model.is_some() {
130	            " pricing=estimated-default"
131	        } else {
132	            ""
133	        };
134	        vec![
135	            format!(
136	                "{label}: total_tokens={} input={} output={} cache_write={} cache_read={} estimated_cost={}{}{}",
137	                self.total_tokens(),
138	                self.input_tokens,
139	                self.output_tokens,
140	                self.cache_creation_input_tokens,
141	                self.cache_read_input_tokens,
142	                format_usd(cost.total_cost_usd()),
143	                model_suffix,
144	                pricing_suffix,
145	            ),
146	            format!(
147	                "  cost breakdown: input={} output={} cache_write={} cache_read={}",
148	                format_usd(cost.input_cost_usd),
149	                format_usd(cost.output_cost_usd),
150	                format_usd(cost.cache_creation_cost_usd),
151	                format_usd(cost.cache_read_cost_usd),
152	            ),
153	        ]
154	    }
155	}
