192	    pub fn record(&mut self, usage: TokenUsage) {
193	        self.latest_turn = usage;
194	        self.cumulative.input_tokens += usage.input_tokens;
195	        self.cumulative.output_tokens += usage.output_tokens;
196	        self.cumulative.cache_creation_input_tokens += usage.cache_creation_input_tokens;
197	        self.cumulative.cache_read_input_tokens += usage.cache_read_input_tokens;
198	        self.turns += 1;
199	    }
