145	    pub fn lookup_completion(&self, request: &MessageRequest) -> Option<MessageResponse> {
146	        let request_hash = request_hash_hex(request);
147	        let (paths, ttl) = {
148	            let inner = self.lock();
149	            (inner.paths.clone(), inner.config.completion_ttl)
150	        };
151	        let entry_path = paths.completion_entry_path(&request_hash);
152	        let entry = read_json::<CompletionCacheEntry>(&entry_path);
153	        let Some(entry) = entry else {
154	            let mut inner = self.lock();
155	            inner.stats.completion_cache_misses += 1;
156	            inner.stats.last_completion_cache_key = Some(request_hash);
157	            persist_state(&inner);
158	            return None;
159	        };
160	
161	        if entry.fingerprint_version != current_fingerprint_version() {
162	            let mut inner = self.lock();
163	            inner.stats.completion_cache_misses += 1;
164	            inner.stats.last_completion_cache_key = Some(request_hash.clone());
165	            let _ = fs::remove_file(entry_path);
166	            persist_state(&inner);
167	            return None;
168	        }
169	
170	        let expired = now_unix_secs().saturating_sub(entry.cached_at_unix_secs) >= ttl.as_secs();
171	        let mut inner = self.lock();
172	        inner.stats.last_completion_cache_key = Some(request_hash.clone());
173	        if expired {
174	            inner.stats.completion_cache_misses += 1;
175	            let _ = fs::remove_file(entry_path);
176	            persist_state(&inner);
177	            return None;
178	        }
179	
180	        inner.stats.completion_cache_hits += 1;
181	        apply_usage_to_stats(
182	            &mut inner.stats,
183	            &entry.response.usage,
184	            &request_hash,
185	            "completion-cache",
186	        );
187	        inner.previous = Some(TrackedPromptState::from_usage(
188	            request,
189	            &entry.response.usage,
190	        ));
191	        persist_state(&inner);
192	        Some(entry.response)
193	    }
