209	    fn record_usage_internal(
210	        &self,
211	        request: &MessageRequest,
212	        usage: &Usage,
213	        response: Option<&MessageResponse>,
214	    ) -> PromptCacheRecord {
215	        let request_hash = request_hash_hex(request);
216	        let mut inner = self.lock();
217	        let previous = inner.previous.clone();
218	        let current = TrackedPromptState::from_usage(request, usage);
219	        let cache_break = detect_cache_break(&inner.config, previous.as_ref(), &current);
220	
221	        inner.stats.tracked_requests += 1;
222	        apply_usage_to_stats(&mut inner.stats, usage, &request_hash, "api-response");
223	        if let Some(event) = &cache_break {
224	            if event.unexpected {
225	                inner.stats.unexpected_cache_breaks += 1;
226	            } else {
227	                inner.stats.expected_invalidations += 1;
228	            }
229	            inner.stats.last_break_reason = Some(event.reason.clone());
230	        }
231	
232	        inner.previous = Some(current);
233	        if let Some(response) = response {
234	            write_completion_entry(&inner.paths, &request_hash, response);
235	            inner.stats.completion_cache_writes += 1;
236	        }
237	        persist_state(&inner);
238	
239	        PromptCacheRecord {
240	            cache_break,
241	            stats: inner.stats.clone(),
242	        }
243	    }
