492	fn stable_hash_bytes(bytes: &[u8]) -> u64 {
493	    let mut hash = FNV_OFFSET_BASIS;
494	    for byte in bytes {
495	        hash ^= u64::from(*byte);
496	        hash = hash.wrapping_mul(FNV_PRIME);
497	    }
498	    hash
499	}
