147	        let (paths, ttl) = {
148	            let inner = self.lock();
149	            (inner.paths.clone(), inner.config.completion_ttl)
150	        };
151	        let entry_path = paths.completion_entry_path(&request_hash);
152	        let entry = read_json::<CompletionCacheEntry>(&entry_path);
153	        let Some(entry) = entry else {
154	            let mut inner = self.lock();
155	            inner.stats.completion_cache_misses += 1;
156	            inner.stats.last_completion_cache_key = Some(request_hash);
