314	fn detect_cache_break(
315	    config: &PromptCacheConfig,
316	    previous: Option<&TrackedPromptState>,
317	    current: &TrackedPromptState,
318	) -> Option<CacheBreakEvent> {
319	    let previous = previous?;
320	    if previous.fingerprint_version != current.fingerprint_version {
321	        return Some(CacheBreakEvent {
322	            unexpected: false,
323	            reason: format!(
324	                "fingerprint version changed (v{} -> v{})",
325	                previous.fingerprint_version, current.fingerprint_version
326	            ),
327	            previous_cache_read_input_tokens: previous.cache_read_input_tokens,
328	            current_cache_read_input_tokens: current.cache_read_input_tokens,
329	            token_drop: previous
330	                .cache_read_input_tokens
331	                .saturating_sub(current.cache_read_input_tokens),
332	        });
333	    }
334	    let token_drop = previous
335	        .cache_read_input_tokens
336	        .saturating_sub(current.cache_read_input_tokens);
337	    if token_drop < config.cache_break_min_drop {
338	        return None;
339	    }
340	
341	    let mut reasons = Vec::new();
342	    if previous.model_hash != current.model_hash {
343	        reasons.push("model changed");
344	    }
345	    if previous.system_hash != current.system_hash {
346	        reasons.push("system prompt changed");
347	    }
348	    if previous.tools_hash != current.tools_hash {
349	        reasons.push("tool definitions changed");
350	    }
351	    if previous.messages_hash != current.messages_hash {
352	        reasons.push("message payload changed");
353	    }
354	
355	    let elapsed = current
356	        .observed_at_unix_secs
357	        .saturating_sub(previous.observed_at_unix_secs);
358	
359	    let (unexpected, reason) = if reasons.is_empty() {
360	        if elapsed > config.prompt_ttl.as_secs() {
361	            (
362	                false,
363	                format!("possible prompt cache TTL expiry after {elapsed}s"),
364	            )
365	        } else {
366	            (
367	                true,
368	                "cache read tokens dropped while prompt fingerprint remained stable".to_string(),
369	            )
370	        }
371	    } else {
372	        (false, reasons.join(", "))
373	    };
374	
375	    Some(CacheBreakEvent {
376	        unexpected,
377	        reason,
378	        previous_cache_read_input_tokens: previous.cache_read_input_tokens,
379	        current_cache_read_input_tokens: current.cache_read_input_tokens,
380	        token_drop,
381	    })
382	}
